    25ŌåÆ	return func(next http.Handler) http.Handler {
    26ŌåÆ		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    27ŌåÆ			// Try Bearer token first
    28ŌåÆ			if header := r.Header.Get("Authorization"); strings.HasPrefix(header, "Bearer ") {
    29ŌåÆ				rawKey := strings.TrimPrefix(header, "Bearer ")
