    31ŌåÆ				if err != nil || !valid {
    32ŌåÆ					RespondError(w, r, http.StatusUnauthorized, "unauthorized", "Invalid API key")
    33ŌåÆ					return
    34ŌåÆ				}
    35ŌåÆ				go store.TouchKeyUsage(context.Background(), rawKey)
    36ŌåÆ				next.ServeHTTP(w, r)
