    56ŌåÆfunc RateLimit(rps float64, burst int) Middleware {
    57ŌåÆ	var mu sync.Mutex
    58ŌåÆ	limiters := make(map[string]*rate.Limiter)
    59ŌåÆ	getLimiter := func(key string) *rate.Limiter {
    60ŌåÆ		mu.Lock()
    61ŌåÆ		defer mu.Unlock()
    62ŌåÆ		if lim, ok := limiters[key]; ok {
    63ŌåÆ			return lim
    64ŌåÆ		}
    65ŌåÆ		lim := rate.NewLimiter(rate.Limit(rps), burst)
    66ŌåÆ		limiters[key] = lim
    67ŌåÆ		return lim
    68ŌåÆ	}
    69ŌåÆ	return func(next http.Handler) http.Handler {
    70ŌåÆ		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    71ŌåÆ			key := r.RemoteAddr
    72ŌåÆ			if auth := r.Header.Get("Authorization"); strings.HasPrefix(auth, "Bearer ") {
    73ŌåÆ				key = strings.TrimPrefix(auth, "Bearer ")
    74ŌåÆ			}
    75ŌåÆ			lim := getLimiter(key)
    76ŌåÆ			if !lim.Allow() {
    77ŌåÆ				w.Header().Set("Retry-After", "1")
    78ŌåÆ				RespondError(w, r, http.StatusTooManyRequests, "rate_limited", "Too many requests")
    79ŌåÆ				return
    80ŌåÆ			}
    81ŌåÆ			next.ServeHTTP(w, r)
    82ŌåÆ		})
    83ŌåÆ	}
    84ŌåÆ}
