    19ŌåÆ
    20ŌåÆ// NewOrchestrator creates an orchestrator that dynamically loads enabled
    21ŌåÆ// sources from the database on each poll cycle.
    22ŌåÆfunc NewOrchestrator(service *Service, loader *SourceLoader, pool *pgxpool.Pool, interval time.Duration) *Orchestrator {
    23ŌåÆ	return &Orchestrator{service: service, loader: loader, pool: pool, interval: interval}
    24ŌåÆ}
    25ŌåÆ
    26ŌåÆ// NewOrchestratorWithSources creates an orchestrator with a static source list.
    27ŌåÆ// Intended for testing; production code should use NewOrchestrator with a SourceLoader.
    28ŌåÆfunc NewOrchestratorWithSources(service *Service, sources []IIngestionSource, interval time.Duration) *Orchestrator {
    29ŌåÆ	return &Orchestrator{service: service, staticSources: sources, interval: interval}
