    31ŌåÆ
    32ŌåÆ// Run polls all sources immediately, then on every tick. Blocks until ctx is cancelled.
    33ŌåÆfunc (o *Orchestrator) Run(ctx context.Context) {
    34ŌåÆ	ticker := time.NewTicker(o.interval)
    35ŌåÆ	defer ticker.Stop()
    36ŌåÆ
    37ŌåÆ	o.pollAll(ctx)
    38ŌåÆ
    39ŌåÆ	for {
    40ŌåÆ		select {
    41ŌåÆ		case <-ctx.Done():
    42ŌåÆ			return
    43ŌåÆ		case <-ticker.C:
    44ŌåÆ			o.pollAll(ctx)
    45ŌåÆ		}
    46ŌåÆ	}
    47ŌåÆ}
    48ŌåÆ
    49ŌåÆfunc (o *Orchestrator) pollAll(ctx context.Context) {
    50ŌåÆ	sources := o.staticSources
    51ŌåÆ	if sources == nil {
    52ŌåÆ		scheduled, err := o.loader.LoadEnabledSources(ctx)
    53ŌåÆ		if err != nil {
    54ŌåÆ			slog.Error("load sources failed", "err", err)
    55ŌåÆ			return
    56ŌåÆ		}
    57ŌåÆ		if len(scheduled) == 0 {
    58ŌåÆ			slog.Debug("no enabled sources to poll")
    59ŌåÆ			return
    60ŌåÆ		}
    61ŌåÆ		now := time.Now()
    62ŌåÆ		for _, ss := range scheduled {
    63ŌåÆ			if ss.LastPolledAt != nil {
    64ŌåÆ				interval := time.Duration(ss.PollIntervalSeconds) * time.Second
    65ŌåÆ				if now.Before(ss.LastPolledAt.Add(interval)) {
    66ŌåÆ					continue
    67ŌåÆ				}
    68ŌåÆ			}
    69ŌåÆ			o.pollSource(ctx, ss.Source)
    70ŌåÆ		}
    71ŌåÆ		return
    72ŌåÆ	}
    73ŌåÆ	if len(sources) == 0 {
    74ŌåÆ		slog.Debug("no enabled sources to poll")
    75ŌåÆ		return
    76ŌåÆ	}
    77ŌåÆ	for _, src := range sources {
    78ŌåÆ		o.pollSource(ctx, src)
    79ŌåÆ	}
    80ŌåÆ}
    81ŌåÆ
    82ŌåÆfunc (o *Orchestrator) pollSource(ctx context.Context, src IIngestionSource) {
    83ŌåÆ	results, err := src.FetchNewReleases(ctx)
    84ŌåÆ	if err != nil {
    85ŌåÆ		slog.Error("poll failed", "source", src.Name(), "err", err)
    86ŌåÆ		o.updateSourcePollStatus(ctx, src.SourceID(), err)
    87ŌåÆ		return
    88ŌåÆ	}
    89ŌåÆ	o.updateSourcePollStatus(ctx, src.SourceID(), nil)
    90ŌåÆ	if len(results) == 0 {
    91ŌåÆ		return
    92ŌåÆ	}
    93ŌåÆ	if err := o.service.ProcessResults(ctx, src.SourceID(), src.Name(), results); err != nil {
    94ŌåÆ		slog.Error("process failed", "source", src.Name(), "err", err)
    95ŌåÆ	}
    96ŌåÆ}
    97ŌåÆ
    98ŌåÆfunc (o *Orchestrator) updateSourcePollStatus(ctx context.Context, sourceID string, pollErr error) {
    99ŌåÆ	if o.pool == nil {
   100ŌåÆ		return
   101ŌåÆ	}
   102ŌåÆ	var lastError *string
   103ŌåÆ	if pollErr != nil {
   104ŌåÆ		s := pollErr.Error()
   105ŌåÆ		lastError = &s
   106ŌåÆ	}
   107ŌåÆ	_, err := o.pool.Exec(ctx,
   108ŌåÆ		`UPDATE sources SET last_polled_at = NOW(), last_error = $1 WHERE id = $2`,
   109ŌåÆ		lastError, sourceID)
   110ŌåÆ	if err != nil {
   111ŌåÆ		slog.Error("update source poll status", "source", sourceID, "err", err)
   112ŌåÆ	}
   113ŌåÆ}
