    46ŌåÆ}) {
    47ŌåÆ  const measureRef = useRef<HTMLDivElement>(null);
    48ŌåÆ  const moreRef = useRef<HTMLSpanElement>(null);
    49ŌåÆ  const [visibleCount, setVisibleCount] = useState<number | null>(null);
    50ŌåÆ
    51ŌåÆ  const items = React.Children.toArray(children);
    52ŌåÆ
    53ŌåÆ  const measure = useCallback(() => {
    54ŌåÆ    const el = measureRef.current;
    55ŌåÆ    if (!el) return;
    56ŌåÆ    const nodes = el.children;
    57ŌåÆ    const itemNodeCount = nodes.length - 2; // exclude label (first) and hidden "moreŌĆ”" span (last)
    58ŌåÆ    // Check if everything fits without overflow
    59ŌåÆ    if (el.scrollHeight <= MAX_HEIGHT + 4) {
    60ŌåÆ      setVisibleCount(items.length);
    61ŌåÆ      return;
    62ŌåÆ    }
    63ŌåÆ    // Measure actual "moreŌĆ”" link width
    64ŌåÆ    const moreWidth = moreRef.current ? moreRef.current.offsetWidth + 8 : 52;
    65ŌåÆ    const containerWidth = el.offsetWidth;
    66ŌåÆ    // First pass: find all items that fit within MAX_HEIGHT (2 lines)
    67ŌåÆ    let lastFitting = 0;
    68ŌåÆ    for (let i = 1; i <= itemNodeCount; i++) {
    69ŌåÆ      const node = nodes[i] as HTMLElement;
    70ŌåÆ      if (node.offsetTop + node.offsetHeight > MAX_HEIGHT) break;
    71ŌåÆ      lastFitting = i;
    72ŌåÆ    }
    73ŌåÆ    // Second pass: walk backward from lastFitting until "moreŌĆ”" fits after the item
    74ŌåÆ    let count = lastFitting;
    75ŌåÆ    while (count > 1) {
    76ŌåÆ      const node = nodes[count] as HTMLElement;
    77ŌåÆ      const nodeBottom = node.offsetTop + node.offsetHeight;
    78ŌåÆ      // If this item is on line 1, "moreŌĆ”" can always wrap to line 2 ŌĆö we're fine
    79ŌåÆ      if (nodeBottom <= LINE_HEIGHT) break;
    80ŌåÆ      // Item is on line 2 ŌĆö check if "moreŌĆ”" fits after it on the same line
    81ŌåÆ      const nodeRight = node.offsetLeft + node.offsetWidth;
    82ŌåÆ      if (nodeRight + moreWidth <= containerWidth) break;
    83ŌåÆ      count--;
    84ŌåÆ    }
    85ŌåÆ    setVisibleCount(Math.max(1, count));
    86ŌåÆ  }, [items.length]);
    87ŌåÆ
    88ŌåÆ  useEffect(() => {
    89ŌåÆ    const raf = requestAnimationFrame(measure);
    90ŌåÆ    const obs = new ResizeObserver(measure);
    91ŌåÆ    if (measureRef.current) obs.observe(measureRef.current);
    92ŌåÆ    return () => {
    93ŌåÆ      cancelAnimationFrame(raf);
    94ŌåÆ      obs.disconnect();
    95ŌåÆ    };
    96ŌåÆ  }, [measure, items.length]);
    97ŌåÆ
    98ŌåÆ  const hasOverflow = visibleCount !== null && visibleCount < items.length;
    99ŌåÆ  const displayed = visibleCount !== null ? items.slice(0, visibleCount) : items;
   100ŌåÆ
   101ŌåÆ  return (
   102ŌåÆ    <div className="relative">
   103ŌåÆ      {/* Hidden measurer ŌĆö renders all items to find cutoff */}
   104ŌåÆ      <div
   105ŌåÆ        ref={measureRef}
   106ŌåÆ        className="text-[13px] leading-7"
   107ŌåÆ        style={{ position: "absolute", visibility: "hidden", top: 0, left: 0, right: 0, pointerEvents: "none" }}
   108ŌåÆ        aria-hidden="true"
   109ŌåÆ      >
   110ŌåÆ        <span className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5">
   111ŌåÆ          {label}:
   112ŌåÆ        </span>
   113ŌåÆ        {items}
   114ŌåÆ        {/* Hidden "moreŌĆ”" to measure its actual width */}
   115ŌåÆ        <span ref={moreRef} className="inline-flex items-baseline text-[12px] font-medium whitespace-nowrap">
   116ŌåÆ          moreŌĆ”
   117ŌåÆ        </span>
   118ŌåÆ      </div>
   119ŌåÆ      {/* Visible section */}
   120ŌåÆ      <div className="text-[13px] leading-7">
   121ŌåÆ        <span
   122ŌåÆ          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-1.5"
   123ŌåÆ          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
   124ŌåÆ        >
   125ŌåÆ          {label}:
   126ŌåÆ        </span>
   127ŌåÆ        {displayed}
   128ŌåÆ        {hasOverflow && (
   129ŌåÆ          <Link
   130ŌåÆ            href={moreHref}
   131ŌåÆ            className="inline-flex items-baseline text-[12px] font-medium hover:underline whitespace-nowrap"
   132ŌåÆ            style={{ color: "#e8601a" }}
   133ŌåÆ          >
   134ŌåÆ            moreŌĆ”
   135ŌåÆ          </Link>
   136ŌåÆ        )}
   137ŌåÆ      </div>
   138ŌåÆ    </div>
   139ŌåÆ  );
   140ŌåÆ}
