    33ŌåÆfunc (s *DockerHubSource) FetchNewReleases(ctx context.Context) ([]IngestionResult, error) {
    34ŌåÆ	url := fmt.Sprintf("%s/v2/repositories/%s/tags/?page_size=25&ordering=last_updated",
    35ŌåÆ		s.baseURL, s.repository)
    36ŌåÆ
    37ŌåÆ	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
    38ŌåÆ	if err != nil {
    39ŌåÆ		return nil, fmt.Errorf("create request: %w", err)
    40ŌåÆ	}
    41ŌåÆ
    42ŌåÆ	resp, err := s.client.Do(req)
    43ŌåÆ	if err != nil {
    44ŌåÆ		return nil, fmt.Errorf("fetch tags: %w", err)
    45ŌåÆ	}
    46ŌåÆ	defer resp.Body.Close()
    47ŌåÆ
    48ŌåÆ	if resp.StatusCode != http.StatusOK {
    49ŌåÆ		return nil, httpStatusError(resp)
    50ŌåÆ	}
    51ŌåÆ
    52ŌåÆ	var body struct {
    53ŌåÆ		Results []struct {
    54ŌåÆ			Name        string `json:"name"`
    55ŌåÆ			LastUpdated string `json:"last_updated"`
    56ŌåÆ		} `json:"results"`
    57ŌåÆ	}
    58ŌåÆ	if err := json.NewDecoder(resp.Body).Decode(&body); err != nil {
    59ŌåÆ		return nil, fmt.Errorf("decode response: %w", err)
    60ŌåÆ	}
    61ŌåÆ
    62ŌåÆ	results := make([]IngestionResult, 0, len(body.Results))
    63ŌåÆ	for _, tag := range body.Results {
    64ŌåÆ		ts, _ := time.Parse(time.RFC3339Nano, tag.LastUpdated)
    65ŌåÆ		results = append(results, IngestionResult{
    66ŌåÆ			Repository: s.repository,
    67ŌåÆ			RawVersion: tag.Name,
    68ŌåÆ			Timestamp:  ts,
    69ŌåÆ		})
    70ŌåÆ	}
    71ŌåÆ	return results, nil
    72ŌåÆ}
