    30ŌåÆ		return fmt.Errorf("begin tx: %w", err)
    31ŌåÆ	}
    32ŌåÆ	defer tx.Rollback(ctx)
    33ŌåÆ
    34ŌåÆ	// Build raw_data from Metadata + Changelog so nothing is lost.
    35ŌåÆ	raw := make(map[string]string)
    36ŌåÆ	for k, v := range result.Metadata {
    37ŌåÆ		raw[k] = v
    38ŌåÆ	}
    39ŌåÆ	if result.Changelog != "" {
    40ŌåÆ		raw["changelog"] = result.Changelog
    41ŌåÆ	}
    42ŌåÆ	rawData, err := json.Marshal(raw)
    43ŌåÆ	if err != nil {
    44ŌåÆ		return fmt.Errorf("marshal raw_data: %w", err)
    45ŌåÆ	}
    46ŌåÆ
    47ŌåÆ	releaseID := uuid.New().String()
    48ŌåÆ	_, err = tx.Exec(ctx,
    49ŌåÆ		`INSERT INTO releases (id, source_id, version, raw_data, released_at) VALUES ($1, $2, $3, $4, $5)`,
    50ŌåÆ		releaseID, sourceID, result.RawVersion, rawData, result.Timestamp,
    51ŌåÆ	)
    52ŌåÆ	if err != nil {
    53ŌåÆ		return fmt.Errorf("insert release: %w", err)
    54ŌåÆ	}
    55ŌåÆ
    56ŌåÆ	_, err = s.river.InsertTx(ctx, tx, queue.NotifyJobArgs{
    57ŌåÆ		ReleaseID: releaseID,
    58ŌåÆ		SourceID:  sourceID,
    59ŌåÆ	}, nil)
    60ŌåÆ	if err != nil {
    61ŌåÆ		return fmt.Errorf("enqueue job: %w", err)
    62ŌåÆ	}
    63ŌåÆ
    64ŌåÆ	if err := tx.Commit(ctx); err != nil {
    65ŌåÆ		return fmt.Errorf("commit: %w", err)
    66ŌåÆ	}
    67ŌåÆ	return nil
    68ŌåÆ}
