   249ŌåÆ// ParseDependencies parses the LLM response into ScannedDependency structs.
   250ŌåÆ// Handles raw JSON arrays and markdown-fenced JSON.
   251ŌåÆfunc ParseDependencies(raw []byte) ([]models.ScannedDependency, error) {
   252ŌåÆ	text := strings.TrimSpace(string(raw))
   253ŌåÆ
   254ŌåÆ	// Strip markdown code fences if present
   255ŌåÆ	if strings.HasPrefix(text, "```") {
   256ŌåÆ		lines := strings.Split(text, "\n")
   257ŌåÆ		if len(lines) > 2 {
   258ŌåÆ			// Remove first and last lines (``` markers)
   259ŌåÆ			lines = lines[1 : len(lines)-1]
   260ŌåÆ			// If last line is also ```, it was already removed
   261ŌåÆ			if len(lines) > 0 && strings.TrimSpace(lines[len(lines)-1]) == "```" {
   262ŌåÆ				lines = lines[:len(lines)-1]
   263ŌåÆ			}
   264ŌåÆ			text = strings.Join(lines, "\n")
   265ŌåÆ		}
   266ŌåÆ	}
   267ŌåÆ
   268ŌåÆ	var deps []models.ScannedDependency
   269ŌåÆ	if err := json.Unmarshal([]byte(text), &deps); err != nil {
   270ŌåÆ		return nil, fmt.Errorf("parse dependencies JSON: %w\nraw: %s", err, text)
   271ŌåÆ	}
   272ŌåÆ	return deps, nil
   273ŌåÆ}
