   159ŌåÆ	ingestionSrc := ingestion.BuildSource(h.httpClient, src.ID, src.Provider, src.Repository)
   160ŌåÆ	if ingestionSrc == nil {
   161ŌåÆ		RespondError(w, r, http.StatusUnprocessableEntity, "unsupported_provider", "Unsupported provider: "+src.Provider)
   162ŌåÆ		return
   163ŌåÆ	}
   164ŌåÆ
   165ŌåÆ	results, err := ingestionSrc.FetchNewReleases(r.Context())
   166ŌåÆ	if err != nil {
   167ŌåÆ		slog.Error("fetch releases failed", "source", src.ID, "err", err)
   168ŌåÆ		_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, err)
   169ŌåÆ		RespondError(w, r, http.StatusBadGateway, "upstream_error", "Failed to fetch releases from upstream")
   170ŌåÆ		return
   171ŌåÆ	}
   172ŌåÆ
   173ŌåÆ	_ = h.store.UpdateSourcePollStatus(r.Context(), src.ID, nil)
   174ŌåÆ
   175ŌåÆ	newCount := 0
   176ŌåÆ	if len(results) > 0 && h.ingestionService != nil {
   177ŌåÆ		for _, result := range results {
   178ŌåÆ			if procErr := h.ingestionService.ProcessResults(r.Context(), src.ID, src.Provider, []ingestion.IngestionResult{result}); procErr != nil {
   179ŌåÆ				slog.Error("process release failed", "source", src.ID, "version", result.RawVersion, "err", procErr)
   180ŌåÆ				continue
   181ŌåÆ			}
   182ŌåÆ			newCount++
   183ŌåÆ		}
   184ŌåÆ	}
