   199ŌåÆ	slog.Info("async poll triggered", "source", sourceID, "provider", provider, "repository", repository)
   200ŌåÆ
   201ŌåÆ	results, err := ingestionSrc.FetchNewReleases(ctx)
   202ŌåÆ	if err != nil {
