            if (scan.status === "completed" && scan.results) {
              scanStates[idx] = { ...scanStates[idx], status: "completed", results: scan.results };
            } else {
              scanStates[idx] = { ...scanStates[idx], status: "failed", error: scan.error || "Unknown error" };
