  if (!loaded) {
    return (
      <div className="flex items-center justify-center py-12">
        <button
          onClick={() => setLoaded(true)}
          className="rounded-lg bg-purple-600 px-6 py-3 text-sm font-semibold text-white hover:bg-purple-700 transition-colors"
        >
          Load your repos
