	}
	if time.Since(c.fetchedAt) > suggestionsCacheTTL {
		delete(h.cache, key)
		return nil, false
	}
	return c.data, true
}

func (h *SuggestionsHandler) setCache(key string, data json.RawMessage) {
	h.mu.Lock()
