			pageRaw, fetchErr := h.githubGet(r.Context(), path)
			if fetchErr != nil {
				if page == 1 {
					RespondError(w, r, http.StatusBadGateway, "upstream_error", fetchErr.Error())
					return
				}
				break
			}
			var pageItems []json.RawMessage
			if err = json.Unmarshal(pageRaw, &pageItems); err != nil {
