type SuggestionsSourceStore interface {
	ListAllSourceRepos(ctx context.Context) ([]models.SourceRepo, error)
}

type suggestionsCache struct {
	data      json.RawMessage
	fetchedAt time.Time
}

type SuggestionsHandler struct {
	client    *http.Client
