			Name:        s.Name,
			FullName:    s.FullName,
			Description: s.Desc,
			Stars:       s.Stars,
			Language:    s.Language,
			URL:         s.URL,
			AvatarURL:   s.Owner.AvatarURL,
			Provider:    "github",
			Tracked:     tracked["github:"+s.FullName],
		})
	}

