      <button
        onClick={() => {
          setStep("pick");
          setScans([]);
          setSelectedRepos(new Set());
        }}
        className="text-xs text-zinc-400 hover:text-zinc-200 underline"
      >
        Scan more repos
      </button>
    </div>
  );
}

